const input = $json;

const systemPrompt = `# Rol
Eres el Supervisor Agent del sistema Innexia AI Strategic Analysis Engine v5.

# Objetivo
Tu función es analizar el input del proyecto, normalizarlo, determinar el perfil estratégico de la iniciativa, identificar prioridades de análisis y preparar un context bundle estructurado para que otros sub-agentes especializados ejecuten los módulos de:
- BMC
- Strategy
- Roadmap
- Finance
- Risks
- Verdict
- Activities

# Instrucciones clave
- No debes desarrollar el análisis completo de cada módulo.
- No debes redactar explicaciones largas.
- Debes sintetizar el contexto y definir un plan de ejecución claro.
- Debes identificar dependencias lógicas entre módulos.
- Debes inferir supuestos razonables si faltan datos.
- Debes responder únicamente en JSON válido.
- No incluyas markdown.
- No incluyas comentarios.
- No incluyas texto fuera del JSON.

# Criterios
Evalúa:
- tipo de iniciativa
- nivel de madurez
- complejidad
- áreas críticas
- dependencias entre módulos
- usuarios objetivo
- propuesta de valor central
- riesgos preliminares
- enfoque de ejecución sugerido

# Formato de salida requerido
{
  "project_profile": {
    "project_type": "",
    "strategic_maturity": "",
    "complexity": "",
    "confidence": 0
  },
  "execution_plan": {
    "run_bmc": true,
    "run_strategy": true,
    "run_roadmap": true,
    "run_finance": true,
    "run_risks": true,
    "run_verdict": true,
    "run_activities": true
  },
  "context_bundle": {
    "normalized_problem": "",
    "objective": "",
    "target_users": [],
    "core_value_hypothesis": "",
    "key_constraints": [],
    "assumptions": []
  },
  "dependencies": [],
  "priority_focus_areas": [],
  "preliminary_risks": []
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    project_profile: {
      type: "object",
      properties: {
        project_type: { type: "string" },
        strategic_maturity: { type: "string" },
        complexity: { type: "string" },
        confidence: { type: "number" }
      },
      required: ["project_type", "strategic_maturity", "complexity", "confidence"]
    },
    execution_plan: {
      type: "object",
      properties: {
        run_bmc: { type: "boolean" },
        run_strategy: { type: "boolean" },
        run_roadmap: { type: "boolean" },
        run_finance: { type: "boolean" },
        run_risks: { type: "boolean" },
        run_verdict: { type: "boolean" },
        run_activities: { type: "boolean" }
      },
      required: ["run_bmc", "run_strategy", "run_roadmap", "run_finance", "run_risks", "run_verdict", "run_activities"]
    },
    context_bundle: {
      type: "object",
      properties: {
        normalized_problem: { type: "string" },
        objective: { type: "string" },
        target_users: { type: "array", items: { type: "string" } },
        core_value_hypothesis: { type: "string" },
        key_constraints: { type: "array", items: { type: "string" } },
        assumptions: { type: "array", items: { type: "string" } }
      },
      required: ["normalized_problem", "objective", "target_users", "core_value_hypothesis", "key_constraints", "assumptions"]
    },
    dependencies: { type: "array", items: { type: "string" } },
    priority_focus_areas: { type: "array", items: { type: "string" } },
    preliminary_risks: { type: "array", items: { type: "string" } }
  },
  required: ["project_profile", "execution_plan", "context_bundle", "dependencies", "priority_focus_areas", "preliminary_risks"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.project_profile = content.project_profile || {};
content.project_profile.project_type = content.project_profile.project_type || "";
content.project_profile.strategic_maturity = content.project_profile.strategic_maturity || "";
content.project_profile.complexity = content.project_profile.complexity || "";
content.project_profile.confidence =
  typeof content.project_profile.confidence === 'number'
    ? content.project_profile.confidence
    : 0;

content.execution_plan = content.execution_plan || {};
content.execution_plan.run_bmc = typeof content.execution_plan.run_bmc === 'boolean' ? content.execution_plan.run_bmc : true;
content.execution_plan.run_strategy = typeof content.execution_plan.run_strategy === 'boolean' ? content.execution_plan.run_strategy : true;
content.execution_plan.run_roadmap = typeof content.execution_plan.run_roadmap === 'boolean' ? content.execution_plan.run_roadmap : true;
content.execution_plan.run_finance = typeof content.execution_plan.run_finance === 'boolean' ? content.execution_plan.run_finance : true;
content.execution_plan.run_risks = typeof content.execution_plan.run_risks === 'boolean' ? content.execution_plan.run_risks : true;
content.execution_plan.run_verdict = typeof content.execution_plan.run_verdict === 'boolean' ? content.execution_plan.run_verdict : true;
content.execution_plan.run_activities = typeof content.execution_plan.run_activities === 'boolean' ? content.execution_plan.run_activities : true;

content.context_bundle = content.context_bundle || {};
content.context_bundle.normalized_problem = content.context_bundle.normalized_problem || "";
content.context_bundle.objective = content.context_bundle.objective || "";
content.context_bundle.target_users = Array.isArray(content.context_bundle.target_users) ? content.context_bundle.target_users : [];
content.context_bundle.core_value_hypothesis = content.context_bundle.core_value_hypothesis || "";
content.context_bundle.key_constraints = Array.isArray(content.context_bundle.key_constraints) ? content.context_bundle.key_constraints : [];
content.context_bundle.assumptions = Array.isArray(content.context_bundle.assumptions) ? content.context_bundle.assumptions : [];

content.dependencies = Array.isArray(content.dependencies) ? content.dependencies : [];
content.priority_focus_areas = Array.isArray(content.priority_focus_areas) ? content.priority_focus_areas : [];
content.preliminary_risks = Array.isArray(content.preliminary_risks) ? content.preliminary_risks : [];

return [{ json: content }];

const data = $json;

if (!data.project_profile || typeof data.project_profile !== 'object') {
  throw new Error('project_profile faltante o inválido');
}

if (!data.execution_plan || typeof data.execution_plan !== 'object') {
  throw new Error('execution_plan faltante o inválido');
}

if (!data.context_bundle || typeof data.context_bundle !== 'object') {
  throw new Error('context_bundle faltante o inválido');
}

if (!Array.isArray(data.dependencies)) {
  throw new Error('dependencies faltante o inválido');
}

if (!Array.isArray(data.priority_focus_areas)) {
  throw new Error('priority_focus_areas faltante o inválido');
}

if (!Array.isArray(data.preliminary_risks)) {
  throw new Error('preliminary_risks faltante o inválido');
}

return [{ json: data }];
